from fastapi import APIRouter, HTTPException
from foundercrisishub.schemas.crisis import CrisisCreate, CrisisRead, CrisisList
from foundercrisishub.services.crisis_service import CrisisService

router = APIRouter()
service = CrisisService()

@router.post("/crises", response_model=CrisisRead)
async def create_crisis(crisis: CrisisCreate):
    return await service.create_crisis(crisis)

@router.get("/crises", response_model=CrisisList)
async def list_crises():
    return await service.list_crises()

@router.get("/crises/{crisis_id}", response_model=CrisisRead)
async def get_crisis(crisis_id: int):
    obj = await service.get_crisis(crisis_id)
    if not obj:
        raise HTTPException(status_code=404, detail="Crisis not found")
    return obj

@router.post("/crises/{crisis_id}/comment")
async def add_comment(crisis_id: int, comment: str):
    await service.add_comment(crisis_id, comment)
    return {"status": "comment added"}

from pydantic_settings import BaseSettings
from functools import lru_cache

class Settings(BaseSettings):
    database_url: str = "sqlite+aiosqlite:///./db.sqlite3"
    cors_origins: str = "*"
    log_level: str = "info"

    class Config:
        env_file = ".env"

@lru_cache()
def get_settings() -> Settings:
    return Settings()
